export default function(e){function t(){}let l=(e=e||{}).AsyncStorage;return t.put=function(t,n,o){l.setItem(""+t,n).then(e=>o(null,1)).then(e=>console.log("ok put")).catch(e=>{console.error("failed saving to asyncstorage",{key:t,data:n}),o(null,0)})},t.get=(t,n)=>{l.getItem(""+t).then(e=>n(null,e)).then(e=>console.log("ok get")).catch(e=>{console.error("failed fetching from asyncstorage",{key:t}),n(null,0)})},t}